import{_ as s,o as r,c as g,a2 as t}from"./chunks/framework.Nkqvsbxc.js";const a=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"scriptures/般若波羅蜜多心經.md","filePath":"scriptures/般若波羅蜜多心經.md"}'),o={name:"scriptures/般若波羅蜜多心經.md"};function i(h,n,u,b,l,e){return r(),g("div",null,[...n[0]||(n[0]=[t('<h2 id="般若波羅蜜多心經" tabindex="-1">般若波羅蜜多心經 <a class="header-anchor" href="#般若波羅蜜多心經" aria-label="Permalink to &quot;般若波羅蜜多心經&quot;">​</a></h2><p>唐三藏法師玄奘奉詔譯</p><p><strong>觀自在菩薩，行深般若波羅蜜多時，照見五蘊皆空，度一切苦厄。</strong><br> guān zì zài pú sà，xíng shēn bō rě bō luó mì duō shí，zhào jiàn wǔ yùn jiē kōng，dù yī qiè kǔ è。<br><strong>舍利子，色不異空，空不異色；色即是空，空即是色。受、想、行、識，亦復如是。</strong><br> shè lì zǐ，sè bù yì kōng，kōng bù yì sè；sè jí shì kōng，kōng jí shì sè。shòu、xiǎng、xíng、shí，yì fù rú shì。<br><strong>舍利子，是諸法空相：不生不滅，不垢不淨，不增不減。</strong><br> shè lì zǐ，shì zhū fǎ kōng xiāng：bù shēng bù miè，bù gòu bù jìng，bù zēng bù jiǎn。<br><strong>是故空中無色，無受想行識；無眼耳鼻舌身意；無色聲香味觸法；</strong><br> shì gù kōng zhōng wú sè，wú shòu xiǎng xíng shí；wú yǎn ěr bí shé shēn yì；wú sè shēng xiāng wèi chù fǎ；<br><strong>無眼界，乃至無意識界；無無明，亦無無明盡；乃至無老死，亦無老死盡。</strong><br> wú yǎn jiè，nǎi zhì wú yì shí jiè；wú wú míng，yì wú wú míng jìn；nǎi zhì wú lǎo sǐ，yì wú lǎo sǐ jìn。<br><strong>無苦、集、滅、道；無智，亦無得。</strong><br> wú kǔ、jí、miè、dào；wú zhì，yì wú dé。<br><strong>以無所得故，菩提薩埵，依般若波羅蜜多故，心無罣礙；無罣礙故，無有恐怖，遠離顛倒夢想，究竟涅槃。</strong><br> yǐ wú suǒ dé gù，pú tí sà duǒ，yī bō rě bō luó mì duō gù，xīn wú guà ài；wú guà ài gù，wú yǒu kǒng bù，yuǎn lí diān dǎo mèng xiǎng，jiū jìng niè pán。<br><strong>三世諸佛，依般若波羅蜜多故，得阿耨多羅三藐三菩提。</strong><br> sān shì zhū fó，yī bō rě bō luó mì duō gù，dé ā nòu duō luó sān miǎo sān pú tí。<br><strong>故知般若波羅蜜多，是大神呪，是大明呪，是無上呪，是無等等呪，能除一切苦，真實不虛。</strong><br> gù zhī bō rě bō luó mì duō，shì dà shén zhòu，shì dà míng zhòu，shì wú shàng zhòu，shì wú děng děng zhòu，néng chú yī qiè kǔ，zhēn shí bù xū。<br><strong>故說般若波羅蜜多呪，即說呪曰：</strong><br> gù shuō bō rě bō luó mì duō zhòu，jí shuō zhòu yuē：<br><strong>揭諦揭諦，波羅揭諦，波羅僧揭諦，菩提薩婆訶。</strong><br> jiē dì jiē dì，bō luó jiē dì，bō luó sēng jiē dì，pú tí sà pó hē。</p><blockquote><p><strong>【誦讀重點註解】</strong></p><ul><li><strong>般若</strong>：讀 <strong>bō rě</strong>，不讀 bān ruò；</li><li>阿耨多羅三藐三菩提：ā nòu duō luó sān miǎo sān pú tí；</li><li><strong>薩婆訶</strong>：結尾咒語，統讀 <strong>sà pó hē</strong>；</li><li>全文共 260 字，寺院日常早課晚課必誦。</li></ul></blockquote>',4)])])}const _=s(o,[["render",i]]);export{a as __pageData,_ as default};
